import{_ as a,o as t,c as r,al as o}from"./chunks/framework.DxuH9_e6.js";const p=JSON.parse('{"title":"News & Updates","description":"","frontmatter":{},"headers":[],"relativePath":"news_updates/index.md","filePath":"news_updates/index.md"}'),n={name:"news_updates/index.md"};function i(s,e,l,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="news-updates" tabindex="-1">News &amp; Updates <a class="header-anchor" href="#news-updates" aria-label="Permalink to &quot;News &amp; Updates&quot;">​</a></h1><h2 id="upcoming-events" tabindex="-1">Upcoming Events <a class="header-anchor" href="#upcoming-events" aria-label="Permalink to &quot;Upcoming Events&quot;">​</a></h2><p>The EO Dashboard is organising and supporting hands-on workshops, hands-on tutorials, and global open competitions. Come meet the ESA-NASA-JAXA team at these various events.</p><ul><li><p><strong>3 - 8 May 2026 - EGU 2026, Vienna, AT</strong></p><ul><li><code>4 May 2026 10:50-11:10</code>; EO Dashboard - An open resource for education and information from ESA, NASA and JAXA at <code>ESA stand in Hall X2, stand X201</code>; walkthrough of the project, website and accompanying tools by Diego Moglioni.</li><li><code>6 May 2026 11:50-12:10 &amp; 16:20-16:40</code>; Hands-on scientific storytelling with EODashboard team <a href="https://calendar.app.google/hehfJCLMYM9qbZa5A" target="_blank" rel="noreferrer">Tentatively book a slot with us</a> or just come by the <code>ESA stand in Hall X2, stand X201</code>; Explore possibilities for scientific storytelling on your research use cases or our examples. Learn how to use and contribute data and stories to and from EODashboard ecosystem.</li><li>Poster <a href="https://meetingorganizer.copernicus.org/EGU26/EGU26-20206.html" target="_blank" rel="noreferrer">Building Connected Earth Observation Ecosystems with Agentic AI using EVE</a>; Featuring also connection to EODashboard data and stories Thursday, 07 May, 16:15–18:00 (CEST), Display time Thursday, 07 May, 14:00–18:00 Hall X4, X4.68</li><li><code>6 May 2026 10:50-11:10</code>; RACE Dashboard - EO Based information for citizens <code>ESA stand in Hall X2, stand X201</code>; demonstration by Diego Moglioni.</li></ul></li><li><p><strong>9 - 14 August 2026 - IGARSS 2026, Washington DC, US</strong></p><ul><li><a href="https://2026.ieeeigarss.org/tutorials.php#tut8" target="_blank" rel="noreferrer">HD-01; Cloud-Native FAIR EO with NASA, ESA &amp; JAXA Data for Scientific Interactive Storytelling Tutorial</a> - Hands-on tutorial through the end-to-end process of working with EO data in the cloud to develop EO-based indicators using FAIR workflows, publish the indicators and workflows in a STAC catalogue and disseminate the results via engaging and interactive visual and AI-assisted scientific storytelling;</li></ul></li></ul><h2 id="latest-news" tabindex="-1">Latest News <a class="header-anchor" href="#latest-news" aria-label="Permalink to &quot;Latest News&quot;">​</a></h2><ul><li><p><strong>20 Jun 2025 — EO Dashboard upgraded to new interface</strong><br> We have upgraded the eodashboard.org to a completely new interface based on <a href="https://github.com/eodash/eodash" target="_blank" rel="noreferrer">eodash v5</a>. Some collections are still in the process of being fully migrated to offer full expected functionality.</p></li><li><p><strong>10 Mar 2025 — Survey: AI-Powered Features</strong><br> We’re exploring expanding the use of machine-learning on EO Dashboard. <em>Tell us what you’d like to see!</em><a href="https://forms.office.com/Pages/ResponsePage.aspx?id=0Kxcmu8r102sXH6-H1T0laW1G4eQe39LnE1OD1qEn2xUODdPSEJUV0pKU1E1NFZXNDFIQUs4T1o1Sy4u" target="_blank" rel="noreferrer"> &gt;&gt; Fill out the 3-minute questionnaire</a></p></li><li><p><strong>05 Feb 2025 — Agencies Extend Partnership</strong><br> ESA, NASA &amp; JAXA sign a joint declaration committing to EO Dashboard through <strong>September 2026</strong>. Future plans involve integrating cutting-edge technologies, incorporating data from new science missions like EarthCARE and PACE, supporting new joint scientific research, and launching new outreach efforts. <a href="https://raw.githubusercontent.com/eurodatacube/eodash-assets/refs/heads/main/stories/news/2024Joint%20Declaration_draftA-MM-AA_NS_JAXA.pdf" target="_blank" rel="noreferrer">&gt;&gt; Read the declaration</a></p></li></ul><h2 id="blog-posts" tabindex="-1">Blog Posts <a class="header-anchor" href="#blog-posts" aria-label="Permalink to &quot;Blog Posts&quot;">​</a></h2><ul><li><strong><a href="https://eo4society.esa.int/2023/07/03/exploring-open-science-and-geospatial-innovation-the-nasa-esa-jaxa-eo-dashboard-workshop-at-foss4g-2023/" target="_blank" rel="noreferrer">Exploring Open Science &amp; Geospatial Innovation</a></strong> – recap of our FOSS4G workshop.</li><li><strong><a href="https://medium.com/euro-data-cube/creating-powerful-visuals-of-covid-19-impacts-on-human-activities-8879fa75121d" target="_blank" rel="noreferrer">Creating Powerful Visuals of COVID-19 Impacts on Human Activities</a></strong> – Medium article.</li><li><strong><a href="https://medium.com/euro-data-cube/world-food-supply-amid-a-pandemic-3940ef855f07" target="_blank" rel="noreferrer">World Food Supply Amid a Pandemic (Part 1)</a></strong> – Medium series.</li><li><strong><a href="https://medium.com/euro-data-cube/world-food-supply-amid-a-pandemic-87215c8edbdc" target="_blank" rel="noreferrer">World food supply amid a pandemic-Part 2</a></strong> – Medium series.</li><li><strong><a href="https://medium.com/euro-data-cube/lockdown-is-also-changing-our-planet-at-night-520deffec252" target="_blank" rel="noreferrer">Lockdown Is Also Changing Our Planet at Night</a></strong> – Medium article.</li><li><strong><a href="https://medium.com/euro-data-cube/the-pandemic-disruption-of-air-traffic-as-seen-from-space-6dad64201b9a" target="_blank" rel="noreferrer">The Pandemic Disruption of Air Traffic — As Seen from Space</a></strong> – Medium article.</li><li><strong><a href="https://medium.com/euro-data-cube/coronavirus-and-water-quality-whats-the-correlation-bf727d343e61" target="_blank" rel="noreferrer">Coronavirus and Water Quality — what’s the correlation?</a></strong> - Medium article.</li><li><strong><a href="https://medium.com/euro-data-cube/building-traffic-maps-with-space-data-%EF%B8%8F-fd894a847792" target="_blank" rel="noreferrer">Building traffic maps with Space data</a></strong> - Medium article.</li></ul><hr><h3 id="share-your-story" tabindex="-1">Share Your Story <a class="header-anchor" href="#share-your-story" aria-label="Permalink to &quot;Share Your Story&quot;">​</a></h3><p>Working on something society-relevant with EO data from <strong>ESA, NASA, or JAXA</strong>? Send us your idea at <strong><a href="mailto:eodash@esa.int" target="_blank" rel="noreferrer">eodash@esa.int</a></strong> - the most compelling submissions will be featured on this page and across our channels.</p><h2 id="past-events" tabindex="-1">Past Events: <a class="header-anchor" href="#past-events" aria-label="Permalink to &quot;Past Events:&quot;">​</a></h2><ul><li><p><strong>4 – 5 Oct 2025 - NASA Space Apps Challenge, Global, hybrid</strong></p><ul><li><a href="https://www.spaceappschallenge.org" target="_blank" rel="noreferrer">Global Hackathon</a> - <em>form a team, solve a real-world EO challenge, and build your project with EO Dashboard!</em></li></ul></li><li><p><strong>29 Sept – 3 Oct 2025- Big Data from Space, Riga, LV</strong></p><ul><li>Tutorial <a href="https://www.bigdatafromspace2025.org/satellite-event-submission" target="_blank" rel="noreferrer">Hands-on with EO: Creating indicators and stories from open satellite data</a>** - <em>develop new indicators from EO mission data and use them to craft a compelling narrative</em></li></ul></li><li><p><strong>22 – 27 Jun 2025- Living Planet Symposium, Vienna, AT</strong></p><ul><li>Tutorial <a href="https://lps25.esa.int/programme/programme-session/?id=7A4E4BC9-92EE-41D3-8A3A-62FF63DC914E" target="_blank" rel="noreferrer">D.03.18 From Earth Science to Storytelling</a> - <em>build your first dashboard story step-by-step</em></li><li>Demonstration in the EO Arena <a href="https://lps25.esa.int/programme/programme-session/?id=7A613D5A-F956-41EF-B520-EE0A71549B47" target="_blank" rel="noreferrer">D.03.32 DEMO - NASA-ESA-JAXA EO Dashboard</a> - <em>live demo</em></li></ul></li></ul>',13)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
